      "content": "const { sendError } = require('../lib/errors');

function validateProjectName(name) {
  if (!name || typeof name !== 'string' || name.trim() === '') {
    sendError(res, 400, 'INVALID_NAME', 'Project name is required and must be a non-empty string.');
    return false;
  }
  return true;
}

function validateMemberPayload(payload) {
  if (!payload || typeof payload !== 'object' || !payload.userId || !payload.role) {
    sendError(res, 400, 'INVALID_PAYLOAD', 'Member payload must include userId and role.');
    return false;
  }
  return true;
}

function validateCommentPayload(payload) {
  if (!payload || typeof payload !== 'object' || !payload.message) {
    sendError(res, 400, 'INVALID_PAYLOAD', 'Comment payload must include message.');
    return false;
  }
  return true;
}

function validateTaskStatus(status) {
  if (status !== 'todo' && status !== 'done') {
    sendError(res, 400, 'INVALID_STATUS', 'Task status must be either todo or done.');
    return false;
  }
  return true;
}

module.exports = {
  validateProjectName,
  validateMemberPayload,
  validateCommentPayload,
  validateTaskStatus
};
